@namespace sv_f4f8f9e16cbb411596e5775c1172e08f.Components.Pages.Settings

<nav class="settings-sidebar">
    <h5 class="px-3 py-2 text-muted text-uppercase small fw-bold">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in _sections)
        {
            <li class="nav-item">
                <button class="nav-link w-100 text-start @(ActiveSection == section.Key ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section.Key)">
                    <span class="me-2">@section.Icon</span>
                    @section.Label
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private readonly record struct SectionInfo(string Key, string Label, string Icon);

    private static readonly SectionInfo[] _sections =
    [
        new("Profile", "Profile", "👤"),
        new("Notifications", "Notifications", "🔔"),
        new("Security", "Security", "🔒"),
        new("Appearance", "Appearance", "🎨"),
    ];
}

@namespace sv_f4f8f9e16cbb411596e5775c1172e08f.Components.Pages.Settings
@using sv_f4f8f9e16cbb411596e5775c1172e08f.Models

<div class="card">
    <div class="card-body">
        <h4 class="card-title mb-4">Profile Settings</h4>

        <div class="d-flex align-items-center mb-4">
            <div class="me-4">
                @if (!string.IsNullOrWhiteSpace(_avatarUrl))
                {
                    <img src="@_avatarUrl" alt="Avatar" class="rounded-circle" width="80" height="80"
                         style="object-fit: cover;" />
                }
                else
                {
                    <div class="rounded-circle bg-secondary d-flex align-items-center justify-content-center"
                         style="width:80px;height:80px;">
                        <span class="text-white fs-3">👤</span>
                    </div>
                }
            </div>
            <div class="flex-grow-1">
                <label class="form-label small text-muted">Avatar URL</label>
                <input type="url" class="form-control form-control-sm" @bind="_avatarUrl" />
            </div>
        </div>

        <div class="mb-3">
            <label class="form-label">Display Name</label>
            <input type="text" class="form-control" @bind="_displayName" />
        </div>

        <div class="mb-3">
            <label class="form-label">Email</label>
            <input type="email" class="form-control" @bind="_email" />
        </div>

        <div class="mb-3">
            <label class="form-label">Bio</label>
            <textarea class="form-control" rows="4" @bind="_bio"></textarea>
        </div>

        <div class="d-flex gap-2">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save Changes
            </button>
            <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
        </div>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert alert-success mt-3 mb-0 py-2" role="alert">@_message</div>
        }
    </div>
</div>

@code {
    [Parameter] public UserProfile? Profile { get; set; }
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private bool _saving;
    private string? _message;

    protected override void OnParametersSet()
    {
        if (Profile is not null && !_initialized)
        {
            CopyFromProfile();
            _initialized = true;
        }
    }

    private bool _initialized;

    private void CopyFromProfile()
    {
        _displayName = Profile!.DisplayName;
        _email = Profile.Email;
        _avatarUrl = Profile.AvatarUrl;
        _bio = Profile.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await OnSave.InvokeAsync(updated);
        _saving = false;
        _message = "Profile saved successfully!";
    }

    private void Discard()
    {
        if (Profile is not null)
        {
            CopyFromProfile();
        }
        _message = null;
    }
}

@namespace sv_f4f8f9e16cbb411596e5775c1172e08f.Components.Pages.Settings
@using sv_f4f8f9e16cbb411596e5775c1172e08f.Models

<div class="card">
    <div class="card-body">
        <h4 class="card-title mb-4">Notification Preferences</h4>

        <div class="mb-3">
            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
                <label class="form-check-label" for="emailNotif">
                    <strong>Email Notifications</strong>
                    <div class="text-muted small">Receive notifications via email</div>
                </label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
                <label class="form-check-label" for="pushNotif">
                    <strong>Push Notifications</strong>
                    <div class="text-muted small">Receive push notifications in your browser</div>
                </label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">
                    <strong>Weekly Digest</strong>
                    <div class="text-muted small">Get a weekly summary of activity</div>
                </label>
            </div>
        </div>

        <hr />

        <h5 class="mb-3">Muted Channels</h5>
        <p class="text-muted small">Uncheck channels you want to receive notifications from.</p>

        @if (_allChannels.Count > 0)
        {
            <div class="row">
                @foreach (var channel in _allChannels)
                {
                    <div class="col-md-6 mb-2">
                        <div class="form-check">
                            <input class="form-check-input" type="checkbox" id="ch-@channel"
                                   checked="@_mutedSet.Contains(channel)"
                                   @onchange="e => ToggleMute(channel, (bool)(e.Value ?? false))" />
                            <label class="form-check-label" for="ch-@channel">#@channel</label>
                        </div>
                    </div>
                }
            </div>
        }

        <div class="mt-4">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save Preferences
            </button>
        </div>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert alert-success mt-3 mb-0 py-2" role="alert">@_message</div>
        }
    </div>
</div>

@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<string> _allChannels = [];
    private HashSet<string> _mutedSet = [];
    private bool _saving;
    private string? _message;
    private bool _initialized;

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !_initialized)
        {
            _emailNotifications = Prefs.EmailNotifications;
            _pushNotifications = Prefs.PushNotifications;
            _weeklyDigest = Prefs.WeeklyDigest;
            _allChannels = [.. Prefs.MutedChannels];
            _mutedSet = [.. Prefs.MutedChannels];
            _initialized = true;
        }
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted)
            _mutedSet.Add(channel);
        else
            _mutedSet.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        var updated = new NotificationPrefs(
            _emailNotifications,
            _pushNotifications,
            _weeklyDigest,
            [.. _mutedSet]);
        await OnSave.InvokeAsync(updated);
        _saving = false;
        _message = "Notification preferences saved!";
    }
}

@namespace sv_f4f8f9e16cbb411596e5775c1172e08f.Components.Pages.Settings

<div class="card mb-3">
    <div class="card-header d-flex align-items-center justify-content-between"
         style="cursor: pointer;" @onclick="() => _expanded = !_expanded">
        <h5 class="mb-0">Change Password</h5>
        <span>@(_expanded ? "▲" : "▼")</span>
    </div>
    @if (_expanded)
    {
        <div class="card-body">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(_error))
            {
                <div class="alert alert-danger py-2">@_error</div>
            }
            @if (!string.IsNullOrEmpty(_success))
            {
                <div class="alert alert-success py-2">@_success</div>
            }

            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _error;
    private string? _success;
    private bool _saving;

    private async Task UpdatePasswordAsync()
    {
        _error = null;
        _success = null;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _error = "Current password is required.";
            return;
        }
        if (_newPassword.Length < 6)
        {
            _error = "New password must be at least 6 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _error = "New passwords do not match.";
            return;
        }

        _saving = true;
        await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
        _saving = false;
        _success = "Password updated successfully!";
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
    }
}

@namespace sv_f4f8f9e16cbb411596e5775c1172e08f.Components.Pages.Settings
@using sv_f4f8f9e16cbb411596e5775c1172e08f.Models

<div class="card">
    <div class="card-body">
        <h5 class="card-title mb-3">Active Sessions</h5>

        <div class="table-responsive">
            <table class="table table-hover mb-0">
                <thead class="table-light">
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (session.Id != CurrentSessionId)
                                {
                                    <button class="btn btn-outline-danger btn-sm"
                                            @onclick="() => PromptRevoke(session)">
                                        Revoke
                                    </button>
                                }
                                else
                                {
                                    <span class="badge bg-success">Current</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    </div>
</div>

@* Confirmation dialog *@
@if (_sessionToRevoke is not null)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal d-block fade show" tabindex="-1">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong>
                       from <strong>@_sessionToRevoke.Location</strong>?</p>
                    <p class="text-muted small">This will sign out the device immediately.</p>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                    <button class="btn btn-danger" @onclick="ConfirmRevoke" disabled="@_revoking">
                        @if (_revoking)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                        }
                        Revoke Session
                    </button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public string CurrentSessionId { get; set; } = "";
    [Parameter] public EventCallback<string> OnRevoke { get; set; }

    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is null) return;
        _revoking = true;
        await OnRevoke.InvokeAsync(_sessionToRevoke.Id);
        _revoking = false;
        _sessionToRevoke = null;
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

@namespace sv_f4f8f9e16cbb411596e5775c1172e08f.Components.Pages.Settings
@using sv_f4f8f9e16cbb411596e5775c1172e08f.Models

<div class="card">
    <div class="card-body">
        <h4 class="card-title mb-4">Security Settings</h4>

        <ChangePasswordPanel OnChangePassword="OnChangePassword" />

        <div class="card mb-3">
            <div class="card-body d-flex align-items-center justify-content-between">
