                    <strong>Compact Mode</strong>
                    <div class="text-muted small">Reduce spacing and padding throughout the UI</div>
                </label>
            </div>
        </div>

        <hr />

        <AppearancePreview Theme="@_theme" FontSize="@_fontSize" CompactMode="@_compactMode" />

        <div class="mt-4">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save
            </button>
        </div>

        @if (!string.IsNullOrEmpty(_message))
