@namespace sv_f4f8f9e16cbb411596e5775c1172e08f.Components.Pages.Settings

<div class="card border rounded p-3">
    <h6 class="text-muted mb-3">Preview</h6>
    <div class="p-3 rounded" style="@PreviewStyle">
        <h5 style="@FontStyle">Sample Heading</h5>
        <p style="@FontStyle" class="mb-2">
            This is a preview of how your content will look with the selected appearance settings.
        </p>
        <div class="d-flex gap-2">
            <button class="btn btn-sm @ButtonClass">Primary</button>
            <button class="btn btn-sm btn-outline-secondary">Secondary</button>
        </div>
        @if (CompactMode)
        {
            <p class="mt-2 mb-0 small text-muted fst-italic">Compact mode is enabled — reduced spacing.</p>
        }
    </div>
</div>

@code {
    [Parameter] public string Theme { get; set; } = "Light";
    [Parameter] public string FontSize { get; set; } = "Medium";
    [Parameter] public bool CompactMode { get; set; }

    private string PreviewStyle
    {
        get
        {
            var bg = Theme switch
            {
                "Dark" => "background-color: #1e1e2e; color: #cdd6f4;",
                "System" => "background-color: #f0f0f0; color: #333; border: 2px dashed #aaa;",
                _ => "background-color: #ffffff; color: #212529; border: 1px solid #dee2e6;",
            };
            var padding = CompactMode ? "padding: 0.5rem;" : "padding: 1rem;";
            return $"{bg} {padding}";
        }
    }

    private string FontStyle => FontSize switch
    {
        "Small" => "font-size: 0.85rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 1rem;",
    };

    private string ButtonClass => Theme == "Dark" ? "btn-light" : "btn-primary";
}

