@namespace sv_f4f8f9e16cbb411596e5775c1172e08f.Components.Pages.Settings
@using sv_f4f8f9e16cbb411596e5775c1172e08f.Models

<div class="card">
    <div class="card-body">
        <h4 class="card-title mb-4">Appearance</h4>

        <div class="mb-4">
            <label class="form-label fw-semibold">Theme</label>
            <div class="d-flex gap-3">
                @foreach (var theme in _themes)
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme" id="theme-@theme"
                               value="@theme" checked="@(_theme == theme)"
                               @onchange="() => _theme = theme" />
                        <label class="form-check-label" for="theme-@theme">@theme</label>
                    </div>
                }
            </div>
        </div>

        <div class="mb-4">
            <label class="form-label fw-semibold">Font Size</label>
            <div class="d-flex gap-3">
                @foreach (var size in _fontSizes)
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="fontSize" id="fs-@size"
                               value="@size" checked="@(_fontSize == size)"
                               @onchange="() => _fontSize = size" />
                        <label class="form-check-label" for="fs-@size">@size</label>
                    </div>
                }
            </div>
        </div>

        <div class="mb-4">
            <label class="form-label fw-semibold" for="language">Language</label>
            <select class="form-select" id="language" @bind="_language" style="max-width: 300px;">
                @foreach (var lang in _languages)
                {
                    <option value="@lang">@lang</option>
                }
            </select>
        </div>

        <div class="mb-4">
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                <label class="form-check-label" for="compactMode">
                    <strong>Compact Mode</strong>
                    <div class="text-muted small">Reduce spacing and padding throughout the UI</div>
                </label>
            </div>
        </div>

        <hr />

        <AppearancePreview Theme="@_theme" FontSize="@_fontSize" CompactMode="@_compactMode" />

        <div class="mt-4">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save
            </button>
        </div>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert alert-success mt-3 mb-0 py-2" role="alert">@_message</div>
        }
    </div>
</div>

@code {
    [Parameter] public AppearanceSettings? Settings { get; set; }
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _saving;
    private string? _message;
    private bool _initialized;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] _languages =
        ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese"];

    protected override void OnParametersSet()
    {
        if (Settings is not null && !_initialized)
        {
            _theme = Settings.Theme;
            _fontSize = Settings.FontSize;
            _language = Settings.Language;
            _compactMode = Settings.CompactMode;
            _initialized = true;
        }
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await OnSave.InvokeAsync(updated);
        _saving = false;
        _message = "Appearance settings saved!";
    }
}

