@page "/settings"
@namespace sv_f4f8f9e16cbb411596e5775c1172e08f.Components.Pages.Settings
@using sv_f4f8f9e16cbb411596e5775c1172e08f.Models
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

@if (_loading)
{
    <div class="d-flex justify-content-center align-items-center" style="min-height: 400px;">
        <div class="spinner-border text-primary" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else
{
    <div class="settings-layout">
        <aside class="settings-nav">
            <SettingsSidebar ActiveSection="@_activeSection"
                            OnSectionChanged="section => _activeSection = section" />
        </aside>

        <section class="settings-content">
            @switch (_activeSection)
            {
                case "Profile":
                    <ProfileSection Profile="@_profile" OnSave="SaveProfileAsync" />
                    break;

                case "Notifications":
                    <NotificationsSection Prefs="@_notificationPrefs" OnSave="SaveNotificationPrefsAsync" />
                    break;

                case "Security":
                    <SecuritySection Settings="@_securitySettings"
                                     CurrentSessionId="sess-1"
